#!/bin/bash

# Correct: portable shebang
#!/usr/bin/env bash

echo "Hello, Automation!"

function greeting() {
    echo "Hello, $1!"
}

# Or the shorthand syntax
slog() {
    echo "[$(date)] $1"
}

# Execution
greeting "Developer"
slog "System update started"

get_sum() {
    local result=$(( $1 + $2 ))
    echo "$result"
}

total=$(get_sum 10 20)
echo "The total is $total"

cleanup() {
    rm -f "$TMP_FILE"
    echo "Cleanup complete."
}

trap cleanup EXIT INT TERM

while getopts "v:p:" opt; do
  case $opt in
    v) version="$OPTARG" ;;
    p) port="$OPTARG" ;;
    *) usage ;;
  esac
done

log() {
    local level="$1"
    local msg="$2"
    echo "[$(date +'%Y-%m-%dT%H:%M:%S%z')] [$level] $msg" >&2
}

log "INFO" "Initialization complete"
